+/// Wrap a Chat Message in the Add-ons DataActions envelope.
+fn wrap_chat_response(message: serde_json::Value) -> serde_json::Value {
+    serde_json::json!({
+        "hostAppDataAction": {
+            "chatDataActionMarkup": {
+                "createMessageAction": {
+                    "message": message
+                }
+            }
+        }
     })
 }

